import fs from "node:fs";
import path from "node:path";

const ROOT = process.cwd();
const ICONS_DIR = path.join(ROOT, "packages/icons-react/src/icons");
const INDEX = path.join(ROOT, "packages/icons-react/src/index.ts");

const files = fs.existsSync(ICONS_DIR)
  ? fs.readdirSync(ICONS_DIR).filter((f) => f.endsWith(".tsx"))
  : [];

files.sort((a, b) => a.localeCompare(b));

const lines = [
  "// Generated by scripts/generate-react-exports.mjs — do not edit by hand.",
  "",
];

for (const f of files) {
  const base = f.replace(/\.tsx$/u, "");
  lines.push(`export { default as ${base} } from './icons/${base}.js';`);
}

lines.push("");
fs.writeFileSync(INDEX, lines.join("\n"), "utf8");

console.log(`Wrote ${files.length} exports to ${path.relative(ROOT, INDEX)}`);
